from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Group by main subject (airport) and create a complex sentence
    main_subject = list(subject_map.keys())[0] if subject_map else ""
    sentence = main_subject

    # Track relationships to build complex sentences
    location_info = []
    country_info = []
    language_info = []
    leader_info = []
    other_info = []

    for subject, triples in subject_map.items():
        for predicate, obj in triples:
            if predicate == "cityServed":
                other_info.append(f"serves the city of {obj}")
            elif predicate == "mayor":
                other_info.append(f"has a mayor of {obj}")
            elif predicate == "isPartOf":
                location_info.append(f"is part of {obj}")
            elif predicate == "operatingOrganisation":
                other_info.append(f"is operated by {obj}")
            elif predicate == "location":
                location_info.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                other_info.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "runwayLength":
                other_info.append(f"has a runway length of {obj}")
            elif predicate == "country":
                country_info.append(f"is located in {obj}")
            elif predicate == "capital":
                other_info.append(f"has a capital of {obj}")
            elif predicate == "language":
                language_info.append(f"where {obj} is spoken")
            elif predicate == "leader":
                leader_info.append(f"where the leader is {obj}")
            elif predicate == "owner":
                other_info.append(f"is owned by {obj}")
            elif predicate == "1stRunwayLengthFeet":
                other_info.append(f"has a first runway length of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                other_info.append(f"has a first runway surface type of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                other_info.append(f"has a third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                other_info.append(f"has an ICAO location identifier of {obj}")
            elif predicate == "locationIdentifier":
                other_info.append(f"has a location identifier of {obj}")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                other_info.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "iataLocationIdentifier":
                other_info.append(f"has an IATA location identifier of {obj}")
            elif predicate == "nativeName":
                other_info.append(f"has a native name of {obj}")
            elif predicate == "leaderParty":
                other_info.append(f"has a leader party of {obj}")
            else:
                other_info.append(f"has a {predicate} of {obj}")

    # Build complex sentence structure
    if location_info:
        sentence += " " + ", ".join(location_info)
    if country_info:
        sentence += " " + ", ".join(country_info)
    if language_info:
        sentence += " " + " ".join(language_info)
    if leader_info:
        sentence += " " + " ".join(leader_info)
    if other_info:
        if sentence and not sentence.endswith(" "):
            sentence += " and "
        sentence += " ".join(other_info)

    return sentence + "."
